(1, 'Tipe Data, Variabel dan Operator', 'User dapat memahami dan mampu menjelaskan tentang Tipe Data, Variabel, Input-Output, Sequence dan operator ke pemrograman Java', 1, 1, 1, '2023-06-01 04:30:20', '2023-06-01 04:30:20', 1),
(2, 'Sintaks Pemilihan 1', 'User mampu menyelesaikan permasalahan/studi kasus menggunakan sintaks pemilihan 1 dan mengimplementasikannya dalam bahasa pemrograman Java.', 1, 2, 1, '2023-06-01 04:33:08', '2023-06-01 04:33:08', 1),
(3, 'Sintaks Pemilihan 2', 'User memahami tentang operator logika dan mampu menyelesaikan permasalahan dengan menggunakan sintaks pemilihan bersarang', 1, 3, 1, '2023-06-01 04:34:51', '2023-06-01 04:34:51', 1),
(4, 'Sintaks Perulangan 1', 'User memahami serta mampu membuat kode program dalam bahasa Java menggunakan instruksi perulangan.', 1, 4, 1, '2023-06-01 04:35:54', '2023-06-01 04:35:54', 2),
(5, 'Sintaks Perulangan 2', 'User memahami konsep perulangan bersarang dan mampu membuat kode program perulangan bersarang dalam bahasa Java', 1, 5, 1, '2023-06-01 04:38:11', '2023-06-01 04:38:11', 2),
(6, 'Array 1', 'User mampu memahami konsep array satu dimensi, memberikan contoh penggunaan array satu dimensi, membuat kode program menggunakan konsep array satu dimensi', 1, 6, 1, '2023-06-01 04:41:46', '2023-06-01 04:43:34', 2),
(7, 'Array Multidimensi', 'User memahami konsep array 2 dimensi dan membuat kode program dengan menggunakan konsep array multidimensi.', 1, 7, 1, '2023-06-01 04:43:01', '2023-06-01 04:43:01', 3),
(8, 'Fungsi 1', 'User mampu memahami penggunaan fungsi static pada Java dengan parameter dan mengembalikan nilai dan membuat kode program dengan menggunakan fungsi static dan mengeksekusi fungsi tersebut.', 1, 8, 1, '2023-06-01 04:45:03', '2023-06-01 04:45:03', 3),
(9, 'Fungsi 2', 'User memahami konsep fungsi rekursif dan mampu mengimplementasikan fungsi rekursif dalam kode program', 1, 9, 1, '2023-06-01 04:46:33', '2023-06-01 04:46:33', 3);
