(21, 1, 'Tipe Data, Variabel dan Operator', '<p><strong style=\"color: black;\">Studi Kasus:</strong></p><p>Lengkapilah kode program berdasarkan perintah berikut :</p><ul><li>Tambahkan tipe data untuk variabel panjang, lebar, tinggi, Vbalok dan Lbalok berdasarkan nilai yang ada.</li><li>Tambahkan rumus volume balok “panjang * lebar * tinggi” pada variabel Vbalok</li><li>Tambahkan rumus volume balok “2*(panjang * lebar + panjang * tinggi + lebar * tinggi)” pada variabel Lbalok</li></ul><p> </p><pre class=\"ql-syntax\" spellcheck=\"false\">public <span class=\"hljs-keyword\">class</span> <span class=\"hljs-title class_\">TipeData</span> {\r\n      public <span class=\"hljs-keyword\">static</span> <span class=\"hljs-keyword\">void</span> <span class=\"hljs-title function_\">main</span>(<span class=\"hljs-params\"><span class=\"hljs-built_in\">String</span> args[]</span>) {\r\n             … panjang, lebar, tinggi, vBalok, lBalok;\r\n             \r\n             panjang = <span class=\"hljs-number\">10</span>;\r\n             lebar = <span class=\"hljs-number\">6</span>;\r\n             tinggi = <span class=\"hljs-number\">7</span>;\r\n             \r\n             <span class=\"hljs-comment\">// volume balok</span>\r\n             vBalok = ……;\r\n             \r\n             <span class=\"hljs-comment\">// Luas permukaan balok</span>\r\n             lBalok = …..;\r\n             \r\n             <span class=\"hljs-title class_\">System</span>.<span class=\"hljs-property\">out</span>.<span class=\"hljs-title function_\">print</span>(<span class=\"hljs-string\">\"Volume balok = \"</span>+ vBalok + <span class=\"hljs-string\">\", \"</span>);\r\n             <span class=\"hljs-title class_\">System</span>.<span class=\"hljs-property\">out</span>.<span class=\"hljs-title function_\">print</span>(<span class=\"hljs-string\">\"Luas permukaan balok = \"</span>+ lBalok);\r\n             \r\n      }\r\n}\r\n</pre><p><br></p>', NULL, 30, NULL, '2024-03-22 11:31:41', '2024-03-22 11:58:04', '2024-03-22 11:58:04', 1, NULL),
(22, 1, 'Tipe Data, Variabel dan Operator', '<p><strong style=\"color: black;\">Studi Kasus:</strong></p><p>Lengkapilah kode program berdasarkan perintah berikut :</p><ul><li>Tambahkan tipe data untuk variabel panjang, lebar, tinggi, Vbalok dan Lbalok berdasarkan nilai yang ada.</li><li>Tambahkan rumus volume balok “panjang * lebar * tinggi” pada variabel Vbalok</li><li>Tambahkan rumus volume balok “2*(panjang * lebar + panjang * tinggi + lebar * tinggi)” pada variabel Lbalok</li></ul><p>&nbsp;</p><pre class=\"ql-syntax\" spellcheck=\"false\">public <span class=\"hljs-keyword\">class</span> <span class=\"hljs-title class_\">TipeData</span> {\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;public <span class=\"hljs-keyword\">static</span> <span class=\"hljs-keyword\">void</span> <span class=\"hljs-title function_\">main</span>(<span class=\"hljs-params\"><span class=\"hljs-built_in\">String</span> args[]</span>) {\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;… panjang, lebar, tinggi, vBalok, lBalok;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;panjang = <span class=\"hljs-number\">10</span>;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;lebar = <span class=\"hljs-number\">6</span>;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;tinggi = <span class=\"hljs-number\">7</span>;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"hljs-comment\">// volume balok</span>\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;vBalok = ……;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"hljs-comment\">// Luas permukaan balok</span>\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;lBalok = …..;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"hljs-title class_\">System</span>.<span class=\"hljs-property\">out</span>.<span class=\"hljs-title function_\">print</span>(<span class=\"hljs-string\">\"Volume balok = \"</span>+ vBalok + <span class=\"hljs-string\">\", \"</span>);\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"hljs-title class_\">System</span>.<span class=\"hljs-property\">out</span>.<span class=\"hljs-title function_\">print</span>(<span class=\"hljs-string\">\"Luas permukaan balok = \"</span>+ lBalok);\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\r\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;}\r\n}\r\n</pre><p><br></p>', NULL, 30, NULL, '2024-03-22 11:34:10', '2024-03-22 11:44:23', '2024-03-22 11:44:23', 1, NULL),
