INSERT INTO `user_answer` (`id`, `user_id`, `essay_question_id`, `answer`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 2, 1, 'Karena nilai dari variabel tersebut berbentuk bilangan bulat', '2023-06-01 18:47:46', '2023-06-01 18:47:46', NULL),
(2, 2, 2, 'Langkah-langkah perhitungan volume balok adalah mengalikan panjang, lebar, dan tinggi balok. Sedangkan langkah-langkah perhitungan luas permukaan balok adalah menghitung jumlah sisi-sisi balok (2 sisi panjang * lebar, 2 sisi panjang * tinggi, dan 2 sisi lebar * tinggi) kemudian menjumlahkannya.', '2023-06-01 18:47:46', '2023-06-01 18:47:46', NULL),
(3, 2, 3, 'Untuk mengubah nilai panjang, lebar, dan tinggi balok, Anda dapat mengganti nilai pada bagian panjang = 10, lebar = 6, dan tinggi = 7 dengan nilai yang diinginkan', '2023-06-01 18:47:46', '2023-06-01 18:47:46', NULL),
(4, 2, 4, 'If digunakan dalam kode tersebut untuk membuat kondisi atau pernyataan logis. Dalam konteks kode tersebut, if digunakan untuk melakukan pengecekan apakah nilai lebih besar dari 70. Jika kondisi tersebut terpenuhi, yaitu nilai lebih besar dari 70, maka pesan \"Selamat anda lulus!\" akan dicetak. If digunakan untuk memberikan pengambilan keputusan berdasarkan kondisi tertentu, yang memungkinkan eksekusi kode yang berbeda tergantung pada hasil kondisi yang dievaluasi.', '2023-06-01 19:32:48', '2023-06-01 19:32:48', NULL),
(5, 2, 5, 'Alur program dari kode di atas adalah sebagai berikut:\n\n•	Pertama, program akan menjalankan fungsi main yang merupakan titik masuk utama dalam program Java.\n•	Kemudian, sebuah variabel nilai dengan tipe data integer dideklarasikan dan diinisialisasi dengan nilai 80.\n•	Program akan melanjutkan ke blok if, yang akan mengevaluasi apakah nilai lebih besar dari 70.\n•	Jika kondisi dalam blok if (nilai > 70) bernilai true, program akan mengeksekusi pernyataan yang ada di dalam blok if, yaitu mencetak string \"Selamat anda lulus!\" menggunakan System.out.print().\n•	Jika kondisi dalam blok if bernilai false, program akan melanjutkan ke pernyataan setelah blok if dan program akan selesai.', '2023-06-01 19:32:49', '2023-06-01 19:32:49', NULL),
(6, 2, 6, 'Jika nilai variabel “nilai” kurang dari 70, maka tidak akan ada output yang ditampilkan, karena tidak ada pernyataan lain setelah kondisi if.', '2023-06-01 19:32:49', '2023-06-01 19:32:49', NULL),
(7, 2, 7, 'If-else digunakan untuk membagi kondisi menjadi dua kemungkinan. Dalam studi kasus diatas, IF digunakan untuk melakukan pengecekan apakah nilai itemCost lebih besar dari 24. Jika kondisi tersebut terpenuhi, maka variabel order bernilai \"High Value Item!\" akan dicetak. Sedangkan jika nilai itemCost tidak lebih dari 24, maka variabel order bernilai “Low Order Value!”', '2023-06-01 19:45:23', '2023-06-01 19:45:23', NULL),
(8, 2, 8, '•	Mendeklarasikan kelas Order.\n•	Mendeklarasikan method main sebagai method utama yang akan dieksekusi saat program dijalankan.\n•	Mendeklarasikan variabel itemCost dengan tipe data double dan memberikannya nilai 30.99.\n•	Mendeklarasikan variabel order dengan tipe data String dan memberikannya nilai awal berupa string kosong (\"\").\n•	Melakukan pengecekan kondisi menggunakan pernyataan if. Kondisi yang dievaluasi adalah itemCost > 24.00.\n•	Jika kondisi tersebut benar (nilai itemCost lebih besar dari 24.00), maka blok kode di dalam if akan dieksekusi.\n•	Dalam blok if, nilai variabel order diubah menjadi \"High Value Item!\".\n•	Jika kondisi dalam if tidak terpenuhi (nilai itemCost tidak lebih besar dari 24.00), maka blok kode di dalam else akan dieksekusi.\n•	Dalam blok else, nilai variabel order diubah menjadi \"Low Value Item!\".\n•	Setelah blok if-else selesai dieksekusi, pesan yang ada dalam variabel order akan dicetak menggunakan System.out.print.\n•	Output yang ditampilkan akan bergantung pada nilai itemCost. Jika itemCost lebih besar dari 24.00, maka pesan \"High Value Item!\" akan dicetak. Jika tidak, maka pesan \"Low Value Item!\" akan dicetak.', '2023-06-01 19:45:23', '2023-06-01 19:45:23', NULL),
(9, 2, 9, 'Program akan menampilkan output “Low Value Item”', '2023-06-01 19:45:23', '2023-06-01 19:45:23', NULL),
(10, 2, 10, 'Dengan menggunakan default, program akan menangani situasi di mana nilai shipping tidak cocok dengan case-case yang didefinisikan sebelumnya. Default berfungsi sebagai pilihan terakhir yang akan dieksekusi jika tidak ada case yang cocok dengan nilai yang dievaluasi.', '2023-06-01 20:47:17', '2023-06-01 20:47:17', NULL),
(11, 2, 11, 'Alur program dari baris kode switch-case di atas adalah sebagai berikut:\n\nProgram dimulai dengan mendeklarasikan variabel shipping dengan nilai \"Express\" dan variabel shippingCost tanpa nilai awal. Kemudian, program melanjutkan ke switch statement dengan mengevaluasi nilai dari variabel shipping. \n\nProgram akan membandingkan nilai shipping dengan setiap case yang ada. Jika nilai shipping cocok dengan salah satu case, program akan melompat ke blok kode yang sesuai dengan case tersebut.\nJika nilai shipping adalah \"Regular\", maka variabel shippingCost akan diatur menjadi 0.\nJika nilai shipping adalah \"Express\", maka variabel shippingCost akan diatur menjadi 1.75.\nJika nilai shipping tidak cocok dengan case-case di atas, program akan melompat ke blok kode dalam default.\nPada blok kode default, variabel shippingCost akan diatur menjadi 0.50.\n\nSetelah switch statement selesai dieksekusi, program akan mencetak nilai shippingCost dengan menggunakan pernyataan System.out.print(\"Shipping cost: \" + shippingCost);.\nDengan demikian, alur program akan menentukan nilai shippingCost berdasarkan nilai shipping yang dievaluasi menggunakan switch-case.', '2023-06-01 20:47:17', '2023-06-01 20:47:17', NULL),
(12, 2, 12, 'Pada saat nilai shipping tidak bernilai regular maupun express, sehingga mengeluarkan nilai default, yaitu 0.05', '2023-06-01 20:47:17', '2023-06-01 20:47:17', NULL),
(13, 2, 13, 'Karena variabel isMember di rancang untuk menampung nilai salah saja', '2023-06-03 05:19:09', '2023-06-03 05:55:47', NULL),
(14, 2, 14, '•	Jika nilai isMember adalah false, maka program akan masuk kedalam pemilihan else.\n•	Program akan melakukan pengecekan total. Diketahui total adalah 200000, sehingga masuk kedalam blok pemilihan ketiga dengan diskon 15 %\n•	Sehingga, output dari program tersebut adalah “diskon yang didapatkan adalah 10%”', '2023-06-03 05:19:09', '2023-06-03 05:55:47', NULL),
(15, 2, 15, 'program akan mengeluarkan output “diskon yang didapatkan adalah 90%”', '2023-06-03 05:19:09', '2023-06-03 05:34:08', NULL),
(16, 2, 16, 'd', '2023-06-03 06:38:15', '2023-06-03 06:39:41', NULL),
(17, 2, 17, 'b', '2023-06-03 06:38:15', '2023-06-03 06:38:15', NULL),
(18, 2, 18, 'c', '2023-06-03 06:38:15', '2023-06-03 06:38:15', NULL),
(19, 2, 19, 'Pada kode program tersebut, i++ digunakan sebagai operator penambahan (increment) pada variabel i.\n\nKegunaan dari i++ adalah untuk menambahkan nilai 1 pada variabel i setiap kali perulangan dilakukan. Dalam konteks kode program yang diberikan, setiap iterasi perulangan akan mencetak nilai i dan kemudian nilai i akan ditambah 1 menggunakan i++.\n\nSehingga, i++ berguna untuk mengatur aliran perulangan dan menghindari terjadinya perulangan tak terbatas (infinite loop) dengan memastikan bahwa kondisi perulangan pada while-loop (i < number) akan berhenti pada suatu titik saat nilai i mencapai nilai number yang ditentukan.', '2023-06-04 06:27:46', '2023-06-04 06:27:46', NULL),
(20, 2, 20, 'Variabel number diinisialisasi dengan nilai 6, dan variabel i diinisialisasi dengan nilai 1. Kondisi i < number dievaluasi. Jika kondisi tersebut terpenuhi (nilai i kurang dari number), maka blok kode di dalam while loop akan dieksekusi. Jika kondisi tidak terpenuhi, maka program akan keluar dari loop. Di dalam loop, perintah System.out.print(i) akan mencetak nilai i ke layar. \n\nPada iterasi pertama, nilai i adalah 1, sehingga angka 1 akan dicetak. Selanjutnya, perintah i++ akan menambahkan nilai i sebesar 1. Proses di atas akan diulang terus menerus selama kondisi i < number masih terpenuhi. Pada setiap iterasi, nilai i akan bertambah 1 dan angka tersebut akan dicetak ke layar. \n\nLoop akan berhenti saat nilai i sama dengan atau melebihi nilai number, yaitu saat i bernilai 6. Setelah loop selesai, program akan keluar dari blok while dan program akan berakhir.', '2023-06-04 06:27:46', '2023-06-04 06:27:46', NULL),
(21, 2, 21, 'Output dari kode program di atas adalah tidak ada. Hal ini dikarenakan kondisi pada while loop, yaitu i > number, tidak terpenuhi pada awalnya. Karena nilai awal i adalah 1 dan number adalah 6, maka kondisi 1 > 6 akan bernilai false. Oleh karena itu, blok kode dalam while loop tidak akan dieksekusi, sehingga tidak ada output yang dicetak ke layar.', '2023-06-04 06:27:46', '2023-06-04 06:27:46', NULL),
(22, 2, 22, 'Pada program Fibonacci, fungsi dari kode “int next = first + second;” adalah untuk menghitung nilai angka selanjutnya dalam deret Fibonacci.\n\nPada setiap iterasi perulangan, nilai next dihitung dengan menjumlahkan nilai first dan second. Kemudian, nilai next akan menjadi angka baru dalam deret Fibonacci.\n\nMisalnya, pada awalnya first memiliki nilai 0 dan second memiliki nilai 1. Pada iterasi pertama, next akan dihitung sebagai 0 + 1 = 1. Setelah itu, nilai first akan diperbarui menjadi 1 dan nilai second akan diperbarui menjadi 1.\n\nPada iterasi berikutnya, next akan dihitung sebagai 1 + 1 = 2. Proses ini akan terus berlanjut sampai mencapai jumlah angka Fibonacci yang diinginkan.\n\nDengan mengupdate nilai first dan second setiap kali perulangan dilakukan, kita dapat menghasilkan deret Fibonacci dengan benar.', '2023-06-04 06:48:55', '2023-06-04 06:48:55', NULL),
(23, 2, 23, 'Variabel next diinisialisasi dengan hasil penjumlahan first dan second.\nNilai next dicetak menggunakan perintah System.out.print(next + \" \"), sehingga akan mencetak nilai next diikuti dengan spasi. Nilai first diperbarui dengan nilai second. Nilai second diperbarui dengan nilai next. \n\nVariabel i (yang merupakan counter) ditambahkan dengan 1 menggunakan perintah i++. Kondisi i <= n dievaluasi. Jika kondisi tersebut terpenuhi, maka program akan kembali ke langkah 1 dan melanjutkan iterasi berikutnya. Jika kondisi tidak terpenuhi, maka program akan keluar dari loop.\n\nLangkah-langkah 1-6 akan terus diulang sampai kondisi i <= n tidak terpenuhi.', '2023-06-04 06:48:55', '2023-06-04 06:48:55', NULL),
(24, 2, 24, 'Deret Fibonnaci: \n0 1 1 2 3 5 8 13 21', '2023-06-04 06:48:55', '2023-06-04 06:48:55', NULL),
(25, 2, 25, 'Kode program tersebut berfungsi untuk menentukan jumlah baris piramida bintang. Jika 5 diganti menjadi 7, maka baris piramida menjadi 7 baris', '2023-06-04 06:58:24', '2023-06-04 06:58:24', NULL),
(26, 2, 26, 'Perulangan akan dimulai dari nilai 1 dan berakhir pada saat nilai “j” sama dengan atau kurang dari nilai “i”. Saat kondisi terpenuhi, satu bintang akan ditambahkan ke variabel “output”, jumlah bintang akan terus bertambah seiring dengan nilai “i” yang meningkat.', '2023-06-04 06:58:24', '2023-06-04 06:58:24', NULL),
(27, 2, 27, 'Jumlah baris piramida akan bertambah 1 baris, sehingga menjadi 6 baris, dengan baris terakhir memiliki 6 bintang.', '2023-06-04 06:58:24', '2023-06-04 06:58:24', NULL),
(28, 2, 28, 'Yang merubah array menjadi data string adalah baris kode Arrays.toString(topics)', '2023-06-04 07:00:54', '2023-06-04 07:00:54', NULL),
(29, 2, 29, 'Array topics berisi empat elemen yang mewakili topik-topik berita, yaitu \"Opinion\", \"Tech\", \"Science\", dan \"Health\". Variabel topicArray diinisialisasi dengan hasil pemanggilan Arrays.toString(topics). Fungsi Arrays.toString() digunakan untuk mengonversi array topics menjadi string dengan format yang sesuai.\n\nSelanjutnya, perintah System.out.print(topicArray) digunakan untuk mencetak isi dari variabel topicArray, yaitu string yang berisi daftar topik-topik berita yang diubah dari array topics.\nKetika program dijalankan, string yang berisi daftar topik-topik berita akan ditampilkan sebagai output.', '2023-06-04 07:00:54', '2023-06-04 07:00:54', NULL),
(30, 2, 30, 'Error. Karena elemen array berisi bilangan bulat, sedangkan tipe data array adalah String', '2023-06-04 07:00:54', '2023-06-04 07:00:54', NULL),
(31, 2, 31, 'Fungsi dari kode tersebut adalah untuk membatasi jumlah perulangan sebanyak jumlah panjang data dari array nilai.', '2023-06-04 07:05:09', '2023-06-04 07:05:09', NULL),
(34, 2, 32, 'Perulangan akan dimulai dari nilai 0 dan berakhir pada saat nilai “j” kurang dari jumlah panjang array nilai. Saat kondisi terpenuhi, satu nilai akan ditambahkan ke variabel “total', '2023-06-04 07:05:09', '2023-06-04 07:05:09', NULL),
