(963, 39, 29, '1. menginisialisasi variabel array 1 dimensi\n2. mengubah nilai array menjadi string\n3. mencetak hasil array yang telah diubah menjadi string', '2024-06-10 03:07:40', '2024-06-10 03:07:40', NULL),
(964, 39, 30, 'muncul error. karena Arrays.toString untuk type data string pada array', '2024-06-10 03:07:45', '2024-06-10 03:07:45', NULL),
(965, 40, 1, 'Karena untu memberikan hasil pada perhitungan tersebut membutuhkan nilai bilangan bulat atau number', '2024-06-10 03:14:12', '2024-06-10 03:14:12', NULL),
(966, 40, 2, '1.Menginisialisasi terlebih dahulu setiap variabel seperti panjang, lebar, dan tinggi. Kemudian memberikan nilai setiap variabelnya\n2.Menghitung rumus volume balok  yiatu  panjang * lebar * tinggi;\n3.Menghitung rumus luas permukaan balok yaitu 2*(panjang * lebar + panjang * tinggi + lebar * tinggi);\n4.Cetak hasil dengan cara print variabel vBalok untuk volume dan lBalok untuk luas permukaan', '2024-06-10 03:14:20', '2024-06-10 03:14:20', NULL),
(967, 40, 3, 'Dengan langsung mengubah nilai pada setiap variabelnya', '2024-06-10 03:14:25', '2024-06-10 03:14:25', NULL),
(968, 40, 4, 'Untuk pemilihan pada kondisi tertentu, jika sesuai akan dieksekusi', '2024-06-10 03:21:50', '2024-06-10 03:21:50', NULL),
(969, 40, 5, '1.Menginisialisasi variabel nilai dengan tipe data integer dan valuenya yaitu 8.\n2.Terdapat kondisi berupa if jika nilai lebih besar dari 70 maka akan menampilkan selamat anda lulus!\n3.Sehingga jika yang diinputkan berupa 80 maka akan tampil Selamat anda lulus!', '2024-06-10 03:21:57', '2024-06-10 03:21:57', NULL),
(970, 40, 6, 'Tidak ada output', '2024-06-10 03:22:04', '2024-06-10 03:22:04', NULL),
(971, 40, 7, 'Untuk menentukan suatu kondisi perulangan, jika if sesuai dengan kondisi if maka akan dieksekusi proses tersebut jika tidak maka yang dieksekusi adalah proses pada else', '2024-06-10 03:28:51', '2024-06-10 03:28:51', NULL),
(972, 40, 8, '1.Menginisialisasi variabel itemCost dengan tipe data double dan memberi nilai yaitu 30.99\n2.Menginisialisasi variabel order dengan tipe data string dan memberi nilai yaitu kosong/\" \"\n3.Terdapat kondisi jika itemCost lebih dari 24.00 maka akan dicetak High Value Item!\n4.Selain itu maka yang dicetak adalah Low Value Item!\n5.Cetak variabel order', '2024-06-10 03:28:57', '2024-06-10 03:28:57', NULL),
(973, 40, 9, 'Low Value Item!', '2024-06-10 03:29:04', '2024-06-10 03:29:04', NULL),
(974, 40, 10, 'Jika tidak terdapat case yang sesuai makan default yang dijalankan', '2024-06-10 03:34:55', '2024-06-10 03:34:55', NULL),
(975, 40, 11, '1.Menginisialisasi variabel shipping  dengan tipe data string dan nilai yaitu Express\n2.Terdapat case yang pertama Regular maka yang akan dieksekusi 0\n3.Terdapat case yang pertama Express maka yang akan dieksekusi 1.75\n4.Jika tidak ada case yang cocok maka default yang akan dijalankan yaitu 0.50;\n5.Cetak hasil +shippingCost', '2024-06-10 03:35:02', '2024-06-10 03:35:02', NULL),
(976, 40, 12, 'Jika tidak ada case yang cocok maka akan default', '2024-06-10 03:35:09', '2024-06-10 03:35:09', NULL),
(977, 40, 13, 'Karena input yang diberikan hanya dua kondisi yaitu true dan false.', '2024-06-10 03:41:45', '2024-06-10 03:41:45', NULL),
(978, 40, 14, 'Jika isMember false maka, jika total kurang dari 100000 maka akan mendapatkan diskon sebesar 5 . Jika total lebih dari sama dengan 100000 dan total kurang dari sama dengan 150000 maka diskon sebesar 10. Dan jika total lebih dari 150000 maka diskon sebesar 15', '2024-06-10 03:41:50', '2024-06-10 03:41:50', NULL),
(979, 40, 15, 'Maka yang ditampilkan diskon yang didapatkan adalah 10%', '2024-06-10 03:41:56', '2024-06-10 03:41:56', NULL),
(980, 40, 16, 'Yaitu untuk melakukan perulangan dengan kondisi yang sesuai. Atau increment', '2024-06-10 03:50:34', '2024-06-10 03:50:34', NULL),
(981, 40, 17, '1.Menginisialisasi variabel number dengan tipe data integer dan bernilai 6\n2.Terdapat perulangan yaitu i dimulai dari 1 dan kondisi jika i kurang dari number maka perulangan akan dilakukan terus menerus (i++)\n3.Cetak variabel i sesuai kondisi', '2024-06-10 03:50:39', '2024-06-10 03:50:39', NULL),
