(984, 41, 2, 'langkah perhitungan volume :\nvBalok = panjang * lebar * tinggi;\nsehingga vBalok = 10*6*7 = 420\n\nlangkah luas permukaan balok:\nlBalok = 2*(panjang * lebar + panjang * tinggi + lebar * tinggi);\nlBalok = 2*(10*6+10*7+6*7) = 344', '2024-06-10 03:59:57', '2024-06-10 03:59:57', NULL),
(985, 41, 3, 'angka pada variabel nilai panjang, lebar, dan tinggi langsung diganti dengan sesuai kebutuhan', '2024-06-10 04:00:02', '2024-06-10 04:00:02', NULL),
